// Filtrer les posts en attente et prendre le premier
const allPosts = $input.all();

// Chercher le premier post avec status = 'pending'
const pendingPosts = allPosts.filter(item => {
  const status = (item.json.status || '').trim().toLowerCase();
  return status === 'pending';
});

if (pendingPosts.length === 0) {
  // Aucun post en attente — retourner un item vide avec flag
  return [{ json: { found: false, message: 'Aucun post en attente' } }];
}

// Prendre le premier post en attente (ordre du sheet)
const nextPost = pendingPosts[0];

return [{
  json: {
    found: true,
    row_number: nextPost.json.row_number || nextPost.json.__index || 2,
    post_id: nextPost.json.post_id,
    title: nextPost.json.title,
    content: nextPost.json.content,
    type: nextPost.json.type || 'text',
    hashtags: nextPost.json.hashtags || '',
    status: nextPost.json.status
  }
}];

// Construire le payload LinkedIn Share API v2
const post = $input.first().json;

// Concatener contenu + hashtags
let fullText = post.content;
if (post.hashtags && post.hashtags.trim() !== '') {
  fullText = fullText + String.fromCharCode(10) + String.fromCharCode(10) + post.hashtags;
}

// Payload LinkedIn UGC Post API
const payload = {
  author: 'urn:li:person:REPLACE_WITH_LINKEDIN_PERSON_URN',
  lifecycleState: 'PUBLISHED',
  specificContent: {
    'com.linkedin.ugc.ShareContent': {
      shareCommentary: {
        text: fullText
      },
      shareMediaCategory: 'NONE'
    }
  },
  visibility: {
    'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC'
  }
};

return [{
  json: {
    payload: payload,
    post_id: post.post_id,
    title: post.title,
    content_preview: fullText.substring(0, 100) + '...'
  }
}];

// Construire le payload pour l'API Facebook Graph
// POST https://graph.facebook.com/v19.0/{page-id}/feed
const post = $input.first().json;

// Concatener contenu + hashtags (meme texte que LinkedIn)
let fullText = post.content;
if (post.hashtags && post.hashtags.trim() !== '') {
  fullText = fullText + String.fromCharCode(10) + String.fromCharCode(10) + post.hashtags;
}

return [{
  json: {
    message: fullText,
    post_id: post.post_id,
    title: post.title,
    content_preview: fullText.substring(0, 100) + '...'
  }
}];

// Consolider les resultats LinkedIn et Facebook
// Le Merge passe les items dans l'ordre : [0] = LinkedIn response, [1] = Facebook response
const allItems = $input.all();

const linkedinResponse = allItems[0] ? allItems[0].json : {};
const facebookResponse = allItems[1] ? allItems[1].json : {};

// Recuperer les donnees du post original
const originalPost = $('Code Filtrer Post Suivant').first().json;
const linkedinPayloadData = $('Code Construire Payload LinkedIn').first().json;

// Formater la date de publication
const now = new Date();
const dateStr = now.toLocaleDateString('fr-FR', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

// Extraire l'ID du post LinkedIn depuis la response
let linkedinPostId = '';
if (linkedinResponse.id) {
  linkedinPostId = linkedinResponse.id;
} else if (linkedinResponse.headers && linkedinResponse.headers['x-restli-id']) {
  linkedinPostId = linkedinResponse.headers['x-restli-id'];
}

// Extraire l'ID du post Facebook depuis la response
// Format retourne par Graph API : { id: "PAGE_ID_POST_ID" }
let facebookPostId = '';
if (facebookResponse.id) {
  facebookPostId = facebookResponse.id;
}

// Determiner les statuts
const linkedinOk = linkedinPostId !== '';
const facebookOk = facebookPostId !== '';

let publishStatus = 'published';
if (linkedinOk && !facebookOk) publishStatus = 'published_linkedin_only';
if (!linkedinOk && facebookOk) publishStatus = 'published_facebook_only';
if (!linkedinOk && !facebookOk) publishStatus = 'error';

return [{
  json: {
    post_id: originalPost.post_id,
    row_number: originalPost.row_number,
    title: originalPost.title,
    content_preview: linkedinPayloadData.content_preview,
    linkedin_post_id: linkedinPostId,
    facebook_post_id: facebookPostId,
    linkedin_ok: linkedinOk,
    facebook_ok: facebookOk,
    publish_status: publishStatus,
    published_at: dateStr
  }
}];
